import pickle

def beampipe_ingest(manifest_path: str) -> bytes:
    if not manifest_path:
        return pickle.dumps(b'{}')
    s = manifest_path.strip()
    if s.startswith('{') and s.endswith('}'):
        raw = s.encode('utf-8')
    else:
        with open(manifest_path, 'rb') as f:
            raw = f.read()
    return pickle.dumps(raw)

